{
  "$schema": "https://e-menum.net/schemas/module-v1.json",
  "id": "module-loader",
  "name": "module-loader",
  "displayName": "Module Loader",
  "version": "1.0.0",
  "description": "Core module management system providing module discovery, activation, and lifecycle management",

  "type": "core",
  "category": "system",
  "core": true,
  "enabled": true,
  "priority": 1,

  "author": {
    "name": "E-Menum Team",
    "email": "dev@e-menum.net"
  },

  "compatibility": {
    "platform": ">=1.0.0",
    "node": ">=20.0.0"
  },

  "dependencies": {
    "modules": ["auth"],
    "optional": []
  },

  "provides": {
    "routes": true,
    "events": [
      "module.installed",
      "module.activated",
      "module.deactivated",
      "module.uninstalled",
      "module.upgraded"
    ],
    "hooks": [
      "beforeModuleActivate",
      "afterModuleActivate",
      "beforeModuleDeactivate",
      "afterModuleDeactivate"
    ],
    "permissions": [
      "module:read",
      "module:activate",
      "module:deactivate",
      "module:install",
      "module:uninstall",
      "module:manage"
    ],
    "services": [
      "ModuleLoaderService"
    ]
  },

  "requires": {
    "permissions": ["auth:verify"],
    "events": []
  },

  "tier": {
    "minimum": "free",
    "features": {
      "free": ["view_modules"],
      "starter": ["activate_modules"],
      "professional": ["install_modules"],
      "business": ["manage_modules"],
      "enterprise": ["custom_modules", "module_api"]
    }
  },

  "lifecycle": {
    "install": "lifecycle/install.ts",
    "uninstall": "lifecycle/uninstall.ts",
    "activate": "lifecycle/activate.ts",
    "deactivate": "lifecycle/deactivate.ts",
    "upgrade": "lifecycle/upgrade.ts"
  },

  "admin": {
    "menu": {
      "label": "Modules",
      "icon": "ph-puzzle-piece",
      "route": "/admin/modules",
      "order": 90,
      "hidden": false
    }
  },

  "settings": {
    "schema": "settings.schema.json",
    "defaults": {
      "autoDiscovery": true,
      "autoActivateCoreModules": true,
      "checkDependencies": true,
      "enableHotReload": false
    }
  }
}
